### Socket.io with Express

Socket.io provides real-time bidirectional communication between clients and servers.

```bash
npm install socket.io
```

### WebSocket Server Setup

```javascript
const http = require('http');
const express = require('express');
const { Server } = require('socket.io');

const app = express();
const server = http.createServer(app);
const io = new Server(server);

io.on('connection', (socket) => {
  console.log('A user connected:', socket.id);

  socket.on('disconnect', () => {
    console.log('User disconnected:', socket.id);
  });
});

server.listen(3000);
```

### Event Emission

```javascript
// Server to client
io.emit('broadcast', { message: 'Hello everyone' });
socket.emit('private', { message: 'Hello you' });
socket.broadcast.emit('others', { message: 'Hello others' });

// Client to server (listening on socket)
socket.on('chat message', (msg) => {
  io.emit('chat message', msg);
});
```

### Rooms and Namespaces

```javascript
// Join a room
socket.join('room-123');
io.to('room-123').emit('room message', { data: 'For room only' });

// Namespaces
const adminNamespace = io.of('/admin');
adminNamespace.on('connection', (socket) => {
  // Only clients connected to /admin
});
```

### Real-Time Chat Example

```javascript
io.on('connection', (socket) => {
  socket.on('join room', (room) => {
    socket.join(room);
  });

  socket.on('chat message', ({ room, message, user }) => {
    io.to(room).emit('chat message', { user, message, timestamp: Date.now() });
  });
});
```

